  ('glossario_consultor', '[{"termo":"ASSOCIADO","definicao":"Membro da associação. Não usamos o termo cliente."},{"termo":"EVENTOS","definicao":"Departamento responsável por indenizações, consertos e benefícios."},{"termo":"COTA DE PARTICIPAÇÃO","definicao":"Contribuição do associado no reparo. Calculada por categoria, plano e valor FIPE."},{"termo":"TABELA FIPE","definicao":"Preço médio de veículos no mercado nacional. Base para cálculos."},{"termo":"PROPOSTA DE FILIAÇÃO","definicao":"Documento principal com planos, benefícios e coberturas. 100% digital, assinatura em 1h."},{"termo":"CONTRIBUIÇÃO MENSAL","definicao":"Valor pago mensalmente à associação (não confundir com adesão)."},{"termo":"VISTORIA","definicao":"Avaliação do veículo no ato da filiação (31 fotos + vídeo)."},{"termo":"TROCA DE TITULARIDADE","definicao":"Transferência da proteção para novo proprietário (R$50 repasse + nova adesão)."},{"termo":"SUBSTITUIÇÃO DE PLACA","definicao":"Transferência da proteção para outro veículo do mesmo associado."},{"termo":"MIGRAÇÃO","definicao":"Associado vindo de outra proteção. Requer 4 últimos comprovantes. Sem carência."},{"termo":"DESÁGIO","definicao":"Desconto para associados que colocam adesivo publicitário (10% na mensalidade)."}]', 'json', 'operacional'),
